       	            	                	                        	                                                    	                                                                                                                                            	                                	                        	                	                                            	    	                	                                                                            	            	                                                                            	                            	                    	                                	        	                                        	                                            	                            	                	                                    	                	                                                                                                                                                	                                    	                                	                                                                        	                                                	        	                            	                        	                                                            	                	                                    	                                                            	                    	                                    	            	        	                                        	                                    						             // execSync('git push origin main');
       	            	                	                        	                                                    	                                                                                                                                            	                                	                        	                	                                            	    	                	                                                                            	            	                                                                            	                            	                    	                                	        	                                        	                                            	                            	                	                                    	                	                                                                                                                                                	                                    	                                	                                                                        	                                                	        	                            	                        	                                                            	                	                                    	                                                            	                    	                                    	            	        	                                        	                                    						                         console.log("✅ Live website update triggered!");
